Returns a map of variable name -> details.
Input:
    standard_type: "sdtmig"
    version: "3-1-2"
Output:
    {
        "AEACN": {
            "_links": {...},
            "core": "Exp",
            "description": "...",
            "label": "Action Taken with Study Treatment",
        },
        "AEACNOTH": {
            "_links": {...},
            "core": "Perm",
            "description": "...",
            "label": "Other Action Taken",
        },
        ...
    }

